import React, { useState, useEffect } from 'react';
import {
  Container,
  Grid,
  Paper,
  Typography,
  Box,
  Card,
  CardContent,
  CardHeader,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  Divider,
  Button
} from '@mui/material';
import {
  Dashboard as DashboardIcon,
  Flight as PassportIcon,
  Security as SecurityIcon,
  VpnKey as KeyIcon,
  Gavel as GavelIcon,
  Timeline as TimelineIcon,
  CheckCircle as CheckCircleIcon,
  Error as ErrorIcon,
  ListAlt as ListIcon
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';

const AdminDashboard = () => {
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    passport: 0,
    mdl: 0,
    mdoc: 0,
    verifications: 0
  });
  const [health, setHealth] = useState({
    issuer_api: 'unknown',
    passport_engine: 'unknown',
    mdl_engine: 'unknown',
    mdoc_engine: 'unknown',
    inspection_system: 'unknown'
  });

  useEffect(() => {
    fetchStats();
    fetchHealth();
  }, []);

  const fetchStats = async () => {
    try {
      const response = await fetch('/api/admin/stats');
      const data = await response.json();
      setStats(data);
    } catch (error) {
      console.error('Failed to fetch stats:', error);
    }
  };

  const fetchHealth = async () => {
    try {
      const response = await fetch('/api/health');
      const data = await response.json();
      // Map single service health to dashboard format
      setHealth({
        issuer_api: data.status,
        passport_engine: data.status,
        mdl_engine: data.status,
        mdoc_engine: data.status,
        inspection_system: data.status
      });
    } catch (error) {
      console.error('Failed to fetch health:', error);
    }
  };

  const getStatusColor = (status) => {
    return status === 'healthy' ? 'success.main' : 'error.main';
  };

  const getStatusIcon = (status) => {
    return status === 'healthy' ? <CheckCircleIcon color="success" /> : <ErrorIcon color="error" />;
  };

  return (
    <Container maxWidth="lg">
      <Box sx={{ mb: 4 }}>
        <Typography variant="h4" component="h1" gutterBottom>
          <DashboardIcon sx={{ mr: 2, verticalAlign: 'middle' }} />
          Admin Dashboard
        </Typography>
        <Typography variant="subtitle1" color="text.secondary">
          System Overview and Management
        </Typography>
      </Box>

      <Grid container spacing={3}>
        {/* Quick Actions */}
        <Grid item xs={12} md={8}>
          <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column' }}>
            <Typography variant="h6" gutterBottom>
              Management Modules
            </Typography>
            <Grid container spacing={2}>
              <Grid item xs={12} sm={6} md={4}>
                <Button
                  variant="outlined"
                  fullWidth
                  startIcon={<PassportIcon />}
                  onClick={() => navigate('/admin/passport')}
                  sx={{ height: '100%', py: 2 }}
                >
                  Passport Ops
                </Button>
              </Grid>
              <Grid item xs={12} sm={6} md={4}>
                <Button
                  variant="outlined"
                  fullWidth
                  startIcon={<SecurityIcon />}
                  onClick={() => navigate('/admin/csca')}
                  sx={{ height: '100%', py: 2 }}
                >
                  CSCA Manager
                </Button>
              </Grid>
              <Grid item xs={12} sm={6} md={4}>
                <Button
                  variant="outlined"
                  fullWidth
                  startIcon={<KeyIcon />}
                  onClick={() => navigate('/admin/pkd')}
                  sx={{ height: '100%', py: 2 }}
                >
                  PKD Manager
                </Button>
              </Grid>
              <Grid item xs={12} sm={6} md={4}>
                <Button
                  variant="outlined"
                  fullWidth
                  startIcon={<GavelIcon />}
                  onClick={() => navigate('/admin/trust-anchor')}
                  sx={{ height: '100%', py: 2 }}
                >
                  Trust Anchor
                </Button>
              </Grid>
              <Grid item xs={12} sm={6} md={4}>
                <Button
                  variant="outlined"
                  fullWidth
                  startIcon={<TimelineIcon />}
                  onClick={() => navigate('/admin/metrics')}
                  sx={{ height: '100%', py: 2 }}
                >
                  System Metrics
                </Button>
              </Grid>
              <Grid item xs={12} sm={6} md={4}>
                <Button
                  variant="outlined"
                  fullWidth
                  startIcon={<ListIcon />}
                  onClick={() => navigate('/admin/master-lists')}
                  sx={{ height: '100%', py: 2 }}
                >
                  Master Lists
                </Button>
              </Grid>
            </Grid>
          </Paper>
        </Grid>

        {/* System Health */}
        <Grid item xs={12} md={4}>
          <Card>
            <CardHeader title="System Health" />
            <Divider />
            <CardContent>
              <List dense>
                {Object.entries(health).map(([service, status]) => (
                  <ListItem key={service}>
                    <ListItemIcon>
                      {getStatusIcon(status)}
                    </ListItemIcon>
                    <ListItemText 
                      primary={service.replace('_', ' ').toUpperCase()} 
                      secondary={status}
                    />
                  </ListItem>
                ))}
              </List>
            </CardContent>
          </Card>
        </Grid>

        {/* Statistics */}
        <Grid item xs={12}>
          <Paper sx={{ p: 2 }}>
            <Typography variant="h6" gutterBottom>
              Issuance Statistics
            </Typography>
            <Grid container spacing={3}>
              <Grid item xs={6} md={3}>
                <Box sx={{ textAlign: 'center', p: 2, bgcolor: 'primary.light', borderRadius: 1, color: 'white' }}>
                  <Typography variant="h4">{stats.passport}</Typography>
                  <Typography variant="body2">Passports Issued</Typography>
                </Box>
              </Grid>
              <Grid item xs={6} md={3}>
                <Box sx={{ textAlign: 'center', p: 2, bgcolor: 'secondary.light', borderRadius: 1, color: 'white' }}>
                  <Typography variant="h4">{stats.mdl}</Typography>
                  <Typography variant="body2">mDLs Issued</Typography>
                </Box>
              </Grid>
              <Grid item xs={6} md={3}>
                <Box sx={{ textAlign: 'center', p: 2, bgcolor: 'success.light', borderRadius: 1, color: 'white' }}>
                  <Typography variant="h4">{stats.mdoc}</Typography>
                  <Typography variant="body2">mDocs Issued</Typography>
                </Box>
              </Grid>
              <Grid item xs={6} md={3}>
                <Box sx={{ textAlign: 'center', p: 2, bgcolor: 'info.light', borderRadius: 1, color: 'white' }}>
                  <Typography variant="h4">{stats.verifications}</Typography>
                  <Typography variant="body2">Verifications</Typography>
                </Box>
              </Grid>
            </Grid>
          </Paper>
        </Grid>
      </Grid>
    </Container>
  );
};

export default AdminDashboard;
